import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.stream.ActorMaterializer

import scala.concurrent.Future

object WebhookProxyService extends App {

  implicit val system: ActorSystem = ActorSystem("WebhookProxyService")
  implicit val materializer: ActorMaterializer = ActorMaterializer()

  val route =
    post {
      entity(as[String]) { userUrl =>
        val request = HttpRequest(uri = userUrl)
        val futureResponse: Future[HttpResponse] = Http().singleRequest(request)
        futureResponse.map { response =>
          complete(response.entity.dataBytes)
        }
      }
    }

  Http().bindAndHandle(route, "localhost", 8080)
}